#include <bits/stdc++.h>
using namespace std;
#define int unsigned long long
const int maxn=3e6+5,b=131;
int p[maxn],h[maxn];
void init_hash(const string &s) {
	int n=s.length();
	p[0]=1;
	for(int i=1; i<=n; i++) {
		p[i]=p[i-1]*b;
		h[i]=h[i-1]*b+s[i-1];
	}
}
int get_hash(int l,int r) {
	return h[r]-h[l-1]*p[r-l+1];
}
int q;
string s;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>s>>q;
	init_hash(s);
	while(q--){
		int l,r,ll,rr;
		cin>>l>>r>>ll>>rr;
		if(get_hash(l,r)==get_hash(ll,rr)){
			cout<<"Yes";
		}else{
			cout<<"No";
		}
		cout<<"\n";
	}
	return 0;
}
